package main
import "sort"
type Person struct{Name string; Score int}
func Solve(xs []Person) []Person { out:=append([]Person{},xs...); sort.Slice(out, func(i,j int) bool { if out[i].Score==out[j].Score {return out[i].Name<out[j].Name}; return out[i].Score>out[j].Score }); return out }
